(function () {
  var root = $('Webhook').first().json || {};

  function getNested(obj, path) {
    var current = obj;

    for (var i = 0; i < path.length; i++) {
      if (
        current === null ||
        current === undefined ||
        typeof current !== "object"
      ) {
        return "";
      }

      current = current[path[i]];
    }

    return current === null || current === undefined ? "" : current;
  }

  function getSck() {
    var paths = [
      ["body", "data", "purchase", "origin", "sck"],
      ["body", "data", "purchase", "sck"],
      ["body", "data", "purchase", "sckPaymentLink"],
      ["body", "sck"],
      ["body", "query", "sck"],
      ["query", "sck"],
      ["sck"]
    ];

    for (var i = 0; i < paths.length; i++) {
      var value = getNested(root, paths[i]);

      if (value !== null && value !== undefined && String(value).trim() !== "") {
        return value;
      }
    }

    return "";
  }

  var s = String(getSck() || "")
    .replace(/\s*[—–-]\s*C[oó]pia/gi, "")
    .replace(/\s+/g, " ")
    .replaceAll(" — Cópia","")
    .replaceAll(" — Copy","")
    .trim();

  if (!s) return "";

  if (s.indexOf("||") === -1) {
    return s;
  }

  var parts = s
    .split("||")
    .map(function (v) {
      return String(v || "").trim();
    });

  return [
    parts[0] || "",
    parts[1] || "",
    parts[2] || "",
    parts[3] || "",
    parts[4] || ""
  ].join("||");
})()
}}

