  'transacao_do_order_bump',
  'tipo_da_antecipacao_de_assinatura',
  'motivo_de_recusa_de_cartao',
  'ip',
  'hottok',
  'version',
  'id'
];

const numericColumns = new Set([
  'taxa_de_conversao_moeda_de_compra',
  'valor_de_compra_com_impostos',
  'impostos_locais_de_compra_e_taxa_de_parcelamento',
  'valor_de_compra_sem_impostos',
  'taxa_de_conversao_moeda_da_comissao',
  'comissao_bruta_sem_impostos',
  'minha_comissao',
  'comissao_do_produtor',
  'comissao_do_afiliado',
  'comissao_do_coprodutor',
  'taxa_de_processamento',
  'taxa_de_streaming',
  'outras_taxas',
  'quantidade_total_de_parcelas',
  'quantidade_de_cobrancas'
]);

function normalizeValue(value) {
  if (value === undefined || value === null) return null;

  if (typeof value === 'string') {
    const v = value.trim();

    if (
      v === '' ||
      v.toLowerCase() === '(none)' ||
      v.toLowerCase() === 'null' ||
      v.toLowerCase() === 'undefined'
    ) {
      return null;
    }

    return v;
  }

  if (typeof value === 'boolean') {
    return value ? 1 : 0;
  }

  return value;
}

function sqlValue(column, value) {
  value = normalizeValue(value);

  if (value === null) {
    return 'NULL';
  }

  if (numericColumns.has(column)) {
    const n = Number(value);

    if (Number.isFinite(n)) {
      return String(n);
    }

    return 'NULL';
  }

  const escaped = String(value).replace(/'/g, "''");

  return `'${escaped}'`;
}

const rows = items.flatMap(item => {
  if (Array.isArray(item.json)) return item.json;
  return [item.json];
});

const output = [];

for (const row of rows) {
  const data = {};

  for (const column of allowedColumns) {
    if (Object.prototype.hasOwnProperty.call(row, column)) {
      data[column] = normalizeValue(row[column]);
    }
  }

  if (!data.codigo_da_transacao) {
    output.push({
      json: {
        skipped: true,
        reason: 'codigo_da_transacao ausente',
        original: row
      }
    });

    continue;
  }

  const columns = Object.keys(data);

  const insertColumns = columns
    .map(column => `\`${column}\``)
    .join(',\n  ');

  const insertValues = columns
    .map(column => sqlValue(column, data[column]))
    .join(',\n  ');

  const updateClause = columns
    .filter(column => column !== 'codigo_da_transacao')
    .map(column => `\`${column}\` = VALUES(\`${column}\`)`)
    .join(',\n  ');

  const query = `
INSERT INTO ${tableName} (
  ${insertColumns}
) VALUES (
  ${insertValues}
)
ON DUPLICATE KEY UPDATE
  ${updateClause};
`.trim();

  output.push({
    json: {
      codigo_da_transacao: data.codigo_da_transacao,
      query
    }
  });
}

return output;

